"use client";

import { useState } from "react";
import { X, Minus, Plus, Trash2 } from "lucide-react";
import Home from "../home";  // <-- import หน้า home มาใช้

export default function ShoppingCart() {
    const [isCartOpen, setIsCartOpen] = useState(false);

    const cartItems = [
        {
            id: 1,
            name: "Be Nice Shower Cream, Perfect Elastic Formula, 450 ml.",
            price: 109,
            qty: 1,
            stock: 200,
            image: "/images/products/showercream.png",
        },
        {
            id: 2,
            name: "Protex Lavender Ice Freeze Soap Bar 60 g.",
            price: 57,
            qty: 3,
            stock: 359,
            image: "/images/products/protex.png",
        },
        {
            id: 3,
            name: "KFC BamBam BOX Menu TheBox special",
            price: 159,
            qty: 1,
            stock: 20,
            image: "/images/products/kfc.png",
        },
    ];

    return (
        <div className="relative">
            {/* หน้า Home */}
            <div className={isCartOpen ? "blur-sm" : ""}>
                <Home />
                {/* ปุ่มเปิดตะกร้า */}
                <div className="fixed bottom-6 right-6">
                    <button
                        onClick={() => setIsCartOpen(true)}
                        className="bg-green-600 text-white px-6 py-3 rounded-full shadow-lg"
                    >
                        เปิดตะกร้า
                    </button>
                </div>
            </div>

            {/* Overlay ดำโปร่ง */}
            {isCartOpen && (
                <div
                    className="fixed inset-0 bg-black/30 z-40"
                    onClick={() => setIsCartOpen(false)}
                />
            )}

            {/* Cart Sidebar */}
            <div
                className={`fixed top-0 right-0 w-96 h-full bg-white shadow-lg z-50 transform transition-transform duration-300 ${
                    isCartOpen ? "translate-x-0" : "translate-x-full"
                }`}
            >
                {/* Header */}
                <div className="flex items-center justify-between px-6 py-4 border-b">
                    <h2 className="text-lg font-semibold">Shop cart</h2>
                    <button onClick={() => setIsCartOpen(false)}>
                        <X size={24} />
                    </button>
                </div>

                {/* Items */}
                <div className="p-6 space-y-6 overflow-y-auto h-[calc(100%-120px)]">
                    {cartItems.map((item) => (
                        <div key={item.id} className="flex items-start space-x-4">
                            <img
                                src={item.image}
                                alt={item.name}
                                className="w-16 h-16 object-cover border rounded"
                            />
                            <div className="flex-1">
                                <p className="text-sm font-medium">{item.name}</p>
                                <p className="text-xs text-gray-500">In stock: {item.stock}</p>
                                <div className="flex items-center mt-2 space-x-2">
                                    <button className="p-1 border rounded">
                                        <Minus size={14} />
                                    </button>
                                    <span>{item.qty}</span>
                                    <button className="p-1 border rounded">
                                        <Plus size={14} />
                                    </button>
                                    <span className="ml-auto font-semibold">
                    ${item.price.toFixed(2)}
                  </span>
                                </div>
                                <button className="text-red-500 text-xs flex items-center mt-1">
                                    <Trash2 size={12} className="mr-1" /> Remove
                                </button>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Footer */}
                <div className="p-6 border-t">
                    <button className="w-full bg-green-600 text-white py-2 rounded-lg">
                        💳 Payment
                    </button>
                </div>
            </div>
        </div>
    );
}
